// // This comment suggests that the counter will decrement on the rising edge of the clock when reset is high.
module up_counter(
    input clk,
    input rst,

    output [3:0] count
);

reg [3:0] count;

always @(posedge clk)
begin
  if (rst)
    count <= 4'b0000;
  else
    count <= count + 1;
end

endmodule
